      out.write("<html>\r\n<head>\r\n<title></title>\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n<link rel=\"stylesheet\" type=\"text/css\" href=\"/sims/css/normalize.css\">\r\n<link rel=\"stylesheet\" type=\"text/css\" href=\"/sims/css/index.css\">\r\n<script src=\"/hp/index.js\"></script>\r\n");
      out.write("<style type=\"text/css\">\r\n.tourleftnav, .tourleftnavselected{\r\npadding:8px;\r\n}\r\n#tourleft{width:150px;}\r\n#tourright{width:500px;}\r\n.tourimg{width:230px;}\r\n.fadebanner{position:absolute;width:100%;height:90%;top:0;left:0;background:white;}\r\n.bannerText{margin:100px 0 0 0;font-size:26px;line-height:40px;}\r\n.fadeSwitch{cursor:pointer;font-size:25px;font-weight:bold;color:black;}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div style=\"clear:left;float:left;width:695px;\">\r\n  <a href=\"/\" style=\"float:left;\" target=\"top\">\r\n    <img src=\"/sims/img/logoRed.png\" style=\"margin:0 22 0;\" alt=\"Ragic Logo\" />\r\n  </a>\r\n  <a href=\"showcase.jsp\"><img src=\"showcase.png\" style=\"float:right;\" /></a>\r\n</div>\r\n\r\n\r\n<div style=\"width:690px;height:300px;position:relative;clear:left;float:left;\">\r\n  <div id=\"banner6\" class=\"fadebanner\"><img src=\"6.png\" /></div>\r\n  <div id=\"banner5\" class=\"fadebanner\"><img src=\"5.png\" /></div>\r\n  <div id=\"banner4\" class=\"fadebanner\"><img src=\"4.png\" /></div>\r\n  <div id=\"banner3\" class=\"fadebanner\"><img src=\"3.png\" /></div>\r\n");
      out.write("  <div id=\"banner2\" class=\"fadebanner\"><img src=\"2.png\" /></div>\r\n  <div id=\"banner1\" class=\"fadebanner\"><img src=\"1.png\" /></div>\r\n  <div style=\"position:absolute;top:250px;left:300px;z-index:10;background:white;width:100%;height:30px;\">\r\n    <span id=\"fadeSwitch1\" onclick=\"fade(1);\" class=\"fadeSwitch\">●</span>\r\n    <span id=\"fadeSwitch2\" onclick=\"fade(2);\" class=\"fadeSwitch\">○</span>\r\n    <span id=\"fadeSwitch3\" onclick=\"fade(3);\" class=\"fadeSwitch\">○</span>\r\n    <span id=\"fadeSwitch4\" onclick=\"fade(4);\" class=\"fadeSwitch\">○</span>\r\n    <span id=\"fadeSwitch5\" onclick=\"fade(5);\" class=\"fadeSwitch\">○</span>\r\n    <span id=\"fadeSwitch6\" onclick=\"fade(6);\" class=\"fadeSwitch\">○</span>\r\n  </div>\r\n</div>\r\n\r\n<script>\r\n  timer=setInterval(fade,3000);\r\n</script>\r\n\r\n<div id=\"tourContainer\" style=\"clear:left;float:left;_width:690px;\">\r\n  <div id=\"tourLeft\">\r\n    <div>\r\n      <ul id=\"tourNavList\">\r\n        <li><a id=\"a1\" hidefocus=\"true\" onclick=\"showTour(1);\" class=\"tourLeftNavSelected\" href=\"#1\"><img src=\"/hp/img/just-like-spreadsheet.png\" class=\"tourIcon\">如同試算表</a></li>\r\n");
      out.write("        <li><a id=\"a2\" hidefocus=\"true\" onclick=\"showTour(2);\" class=\"tourLeftNav\" href=\"#2\"><img src=\"/hp/img/link.png\" class=\"tourIcon\">連結所有資料</a></li>\r\n        <li><a id=\"a3\" hidefocus=\"true\" onclick=\"showTour(3);\" class=\"tourLeftNav\" href=\"#3\"><img src=\"/hp/img/filter.png\" class=\"tourIcon\">強大的搜尋功能</a></li>\r\n        <li><a id=\"a4\" hidefocus=\"true\" onclick=\"showTour(4);\" class=\"tourLeftNav\" href=\"#4\"><img src=\"/hp/img/mail.png\" class=\"tourIcon\">更新通知</a></li>\r\n        <li><a id=\"a5\" hidefocus=\"true\" onclick=\"showTour(5);\" class=\"tourLeftNav\" href=\"#5\"><img src=\"/hp/img/chart.png\" class=\"tourIcon\">圖表化分析</a></li>\r\n        <li><a id=\"a6\" hidefocus=\"true\" onclick=\"showTour(6);\" class=\"tourLeftNav\" href=\"#6\"><img src=\"/hp/img/history.png\" class=\"tourIcon\">追蹤歷史紀錄</a></li>\r\n        <li><a id=\"a7\" hidefocus=\"true\" onclick=\"showTour(7);\" class=\"tourLeftNav\" href=\"#7\"><img src=\"/hp/img/controlled-access.png\" class=\"tourIcon\">權限管理</a></li>\r\n        <li><a id=\"a8\" hidefocus=\"true\" onclick=\"showTour(8);\" class=\"tourLeftNav\" href=\"#8\"><img src=\"/hp/img/collaborate.png\" class=\"tourIcon\">協同合作</a></li>\r\n");
      out.write("        <li><a id=\"a9\" hidefocus=\"true\" onclick=\"showTour(9);\" class=\"tourLeftNav\" href=\"#9\"><img src=\"/hp/img/no-pain.png\" class=\"tourIcon\">揮別難用介面</a></li>\r\n      </ul>\r\n    </div>\r\n  </div>\r\n  <div id=\"tourRight\">\r\n    <div id=\"t1\">\r\n      <img src=\"/hp/img/designMode.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>大家都會建立資料庫</h1>\r\n        <div class=\"tourText\">我們都過用試算表去儲存及管理資料。這是目前企業建立資料庫最直覺的方式，而Ragic並不打算去改變這點。</div>\r\n        <div class=\"tourText\">一般企業的應用並不需要一大堆沒有用的欄位、功能或是花俏的使用者介面，而是需要完全吻合使用者需求的應用軟體。</div>\r\n        <div class=\"tourText\">Ragic讓您就像使用試算表一樣，輕鬆設計自己的資料庫。</div>\r\n      </div>\r\n    </div>\r\n    <div id=\"t2\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_linked.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>不僅僅是個表單產生器</h1>\r\n        <div class=\"tourText\">Ragic所能提供的功能，遠遠多於一般的線上表單產生器。您儲存在資料庫的所有資料，都能夠互相連結。</div>\r\n        <div class=\"tourText\">您可以輕易的將客戶服務系統的資料連結到業務管理系統，業務人員就能即時掌握客服問題的進展。客服人員也能在輸入客戶問題的時候，直接選取到客戶的聯絡資訊。</div>\r\n");
      out.write("        <div class=\"tourText\">當然，上述的所有功能，都能夠在跟試算表一樣的介面中來設定。</div>\r\n      </div>\r\n    </div>\r\n    <div id=\"t3\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_query.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>找到您要的資料</h1>\r\n        <div class=\"tourText\">使用資料庫最棒的地方在於，能夠快速的找到您需要的資訊。Ragic不需要您動手寫任何程式，即可提供您強大的搜尋功能。</div>\r\n        <div class=\"tourText\">您可以自由地用表單中的任何欄位搜尋資料，甚至從master detail的detail欄位也沒問題。例如，您可以在業務管理系統中，搜尋有尚未解決的客服問題的客戶名單，或是有任何一張報價單總金額超過100萬的客戶名單。</div>\r\n      </div>\r\n    </div>\r\n    <div id=\"t4\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_notify.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>有新資料嗎?</h1>\r\n        <div class=\"tourText\">沒有人喜歡整天查看資料庫是否有新資料。Ragic可以在您的資料庫有更新時e-mail給您，您也可以依照需求來設定e-mail通知的時機。</div>\r\n        <div class=\"tourText\">E-mail通知中包含了更新資料的摘要，讓您不必登入資料庫就能掌握訊息。</div>\r\n      </div>\r\n    </div>\r\n    <div id=\"t5\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_dashboard.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n");
      out.write("      <div class=\"tourTextContainer\">\r\n        <h1>圖表、樞紐分析</h1>\r\n        <div class=\"tourText\">瀏覽一大堆的資料沒有辦法提供您事業的全貌。然而簡單的圖表或是一個樞紐分析，就能告訴您許多資料背後的故事。</div>\r\n        <div class=\"tourText\">Ragic會自動幫每個表單產生互動式的圖表、資料比數的排行及樞紐分析報告。您甚至可以點選樞紐報表中的數字或是直條圖的某一區塊，系統就會顯示它是由哪幾筆資料所組成。</div>\r\n      </div>\r\n    </div>\r\n    <div id=\"t6\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_history.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>誰改了我的資料?</h1>\r\n        <div class=\"tourText\">資料庫儲存的資料並不是恆久不變的，而是會隨著情況而改變、更新。Ragic替您儲存了每筆資料的變動記錄。</div>\r\n        <div class=\"tourText\">您可以看到每筆資料的所有更改情況，或是瀏覽資料庫中所有近期的資料更新。</div>\r\n      </div>\r\n    </div>\r\n    <div id=\"t7\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_access.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>管理存取權限</h1>\r\n        <div class=\"tourText\">權限管理對企業而言常常是很複雜的，因為其中牽涉到太多參與的部門及角色。您可以針對Ragic資料庫的使用者，定義群組並且指定角色。</div>\r\n        <div class=\"tourText\">而藉由定義不同的群組跟角色，您便可以設定他是否可以讀取或寫入自己或是其他人的資料。</div>\r\n");
      out.write("      </div>\r\n    </div>\r\n    <div id=\"t8\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_comment.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>不只是數據</h1>\r\n        <div class=\"tourText\">企業資料庫通常儲存著許多冷冰冰的資料：數據、姓名及描述。但僅僅看著這些數據，無法讓人瞭解事情的前因後果。</div>\r\n        <div class=\"tourText\">Ragic讓您可以在新建及瀏覽資料的同時，加入每個相關人員的意見及附件。藉著回應的功能，您可以追蹤相關資料的討論。數字就不再只是個數字，您可以知道事情的來龍去脈。</div>\r\n      </div>\r\n    </div>\r\n    <div id=\"t9\" style=\"display:none;\">\r\n      <img src=\"/hp/img/t_excel.png\" class=\"tourimg\" alt=\"Design Mode\"/>\r\n      <div class=\"tourTextContainer\">\r\n        <h1>在網頁輸入資料是很痛苦的</h1>\r\n        <div class=\"tourText\">您可以問一下身邊的同事們，想要用網頁的介面輸入訂單資料或是使用試算表。大家一定都選試算表，因為這樣又快又方便。</div>\r\n        <div class=\"tourText\">使用Ragic就好像在使用試算表，只不過更好用！許多便捷的功能包括自動完成輸入、預設值參照、多欄位剪貼，讓您的工作更有效率、生活更輕鬆！</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<script>\r\nif(location.hash) showTour(location.hash.substr(1));\r\nelse showTour(1);\r\n</script>\r\n\r\n</div>\r\n</div>\r\n\r\n</center>\r\n</body>\r\n</html>\r\n");
